var connectionString = configuration.GetConnectionString("Database") ?? throw new InvalidOperationException("Connection string 'DefaultConnection' not found.");

static void ConfigureSqlServer(DbContextOptionsBuilder options, string connString)
{
    options.UseSqlServer(connString, sqlOptions =>
    {
        sqlOptions.EnableRetryOnFailure(
            maxRetryCount: 5,
            maxRetryDelay: TimeSpan.FromSeconds(10),
            errorNumbersToAdd: [10054, -2, 233, 64, 20]);
        sqlOptions.UseQuerySplittingBehavior(QuerySplittingBehavior.SplitQuery);
        sqlOptions.CommandTimeout(60);
    });
}

services.AddTransient<AuditableEntityInterceptor>();
services.AddDbContext<ApplicationDbContext>((sp, opt) =>
{
    ConfigureSqlServer(opt, connectionString);
    opt.AddInterceptors(sp.GetRequiredService<AuditableEntityInterceptor>());
});
services.AddDbContextFactory<ApplicationDbContext>((sp, opt) =>
{
    ConfigureSqlServer(opt, connectionString);
}, ServiceLifetime.Scoped);
